With.Cte:

					SELECT {{
								Fields
									-Dimension: PointsOfSaleSource
										--Table: PointsOfSaleSourceCte
									-Dimension: PointsOfSaleTarget
										--Table: PointsOfSaleTargetCte
									-Dimension: Products 
										--Table: ProductsCte
									-WithComma
	                	   }}
						   {{
								IfRequest
									-Expression: TransferType
										--MIN(TransferReports.TransferType) AS TransferType									
									-Expression: ActualStockOriginStore
										--SUM(TransferReports.ActualStockOriginStore) AS ActualStockOriginStore									
									-Expression: IdealStockOriginStore
										--SUM(TransferReports.IdealStockOriginStore) AS IdealStockOriginStore									
									-Expression: ActualStockDestinationStore
										--SUM(TransferReports.ActualStockDestinationStore) AS ActualStockDestinationStore									
									-Expression: IdealStockDestinationStore
										--SUM(TransferReports.IdealStockDestinationStore) AS IdealStockDestinationStore									
									-Expression: CostPVM
										--SUM(TransferReports.CostPVM) AS CostPVM									
									-Expression: TotalTransfersOut
										--SUM(TransferReports.TotalTransfersOut) AS TotalTransfersOut									
									-Expression: DaysInStore
										--SUM(TransferReports.DaysInStore) AS DaysInStore									
									-Expression: Sales
										--SUM(TransferReports.Sales) AS Sales									
									-Expression: Margin
										--SUM(TransferReports.Margin) AS Margin									
									-Expression: MarginPercentage
										--SUM(TransferReports.MarginPercentage) AS MarginPercentage
							}}
                    FROM Fact.TransferReports
						{{
	                		InnerJoin 
	                			-Dimension: PointsOfSaleSource
	                				--Table: PointsOfSaleSourceCte
								-Table: TransferReports
								-On:PointOfSaleSourcePointOfSaleId-OriginPointOfSaleId
						}}
						{{
	                		InnerJoin 
	                			-Dimension: PointsOfSaleTarget
	                				--Table: PointsOfSaleTargetCte
								-Table: TransferReports
								-On:PointOfSaleTargetPointOfSaleId-DestinationPointOfSaleId
						}}
		            	{{
		            		InnerJoin 
		            			-Dimension: Products 
		            				--Table: ProductsCte
								-Table: TransferReports
								-On: ProductId-ProductId
		            	}}
						{{
							Where
								-DataSource: [Fact].[TransferReports]
									--Table: TransferReports
						}}
						{{
	                		GroupBy
								-Dimension: PointsOfSaleSource
									--Table: PointsOfSaleSourceCte
								-Dimension: PointsOfSaleTarget
									--Table: PointsOfSaleTargetCte
		            			-Dimension: Products 
		            				--Table: ProductsCte
		            	}}
						{{
							Having
								-Expression: TransferType
									--Aggregation: MIN
									--Table: TransferReports
								-Expression: ActualStockDestinationStore
									--Aggregation: SUM
									--Table: TransferReports
						}}
